import { useNodeState } from './baseNode';
import { BaseNode } from './baseNode';

export const ConditionNode = ({ id, data }) => {
  const [nodeState, updateNodeState] = useNodeState(
    {
      operator: data?.operator || '==',
      value: data?.value || '',
      label: data?.label || 'Condition'
    },
    data // Pass data object for updates
  );

  return (
    <BaseNode
      id={id}
      data={data}
      title={nodeState.label}
      accentColor="#8b5cf6"
      className="condition-node"
      inputHandles={[
        { id: 'input-a' },
        { id: 'input-b' }
      ]}
      outputHandles={[
        { id: 'true', style: { top: '30%' } },
        { id: 'false', style: { top: '70%' } }
      ]}
    >
      <label>
        Operator:
        <select 
          value={nodeState.operator}
          onChange={(e) => updateNodeState('operator', e.target.value)}
        >
          <option value="==">Equals</option>
          <option value="!=">Not Equals</option>
          <option value=">">Greater Than</option>
          <option value="<">Less Than</option>
          <option value=">=">Greater or Equal</option>
          <option value="<=">Less or Equal</option>
        </select>
      </label>
      <label>
        Compare Value:
        <input
          type="text"
          value={nodeState.value}
          onChange={(e) => updateNodeState('value', e.target.value)}
          placeholder="Value to compare"
        />
      </label>
    </BaseNode>
  );
};
